//! P4c CERTIFIED TRAJECTORY PREDICTION — forecast each certified-regime object's future state by the
//! conservation law that holds it, CONDITIONALLY (valid only while the regime holds) and
//! SELF-VALIDATINGLY (grade the forecast against what actually happened).
//!
//! This lifts third-eye's object intelligence from "what regime is this object in NOW" (object_intel)
//! to "what will it be at t+Δt, IF the regime holds" — and then, when the clip reaches t+Δt, grades
//! the forecast against the realised state. It is the same §7.5 admission discipline: every forecast
//! is `accept` (a certified conditional prediction), `abstain` (no honest forecast), and cites a
//! green, Init-only, zero-axiom gnosis-math conservation law. third-eye runs NO force solver and NO
//! ML; a forecast is the analytic forward-integration of the conserved quantity the regime certified.
//!
//! WHAT THIS CERTIFIES (the load-bearing honest bounds):
//!  * CONDITIONAL. Every forecast is "IF no new force/torque acts, THEN state(t+Δt) = ...". It is the
//!    forward image of a CONSERVATION LAW, not a claim about the future of the world. The world can
//!    apply a force; the forecast does not predict that force, it predicts the free continuation.
//!  * REGIME-GATED. A forecast is asserted only after the regime has HELD for >= `hold_min` frames.
//!    A longer freely-X run means a better-established conserved quantity, hence a longer trustworthy
//!    horizon. forced/abstain objects get NO forecast (an unresolved or actively-forced object is not
//!    predictable) — honest ABSTAIN.
//!  * INVALIDATED BY INTERACTION. A forecast is EXPIRED the moment the object is on a collision course
//!    (close to + approaching another object) — a freely-translating disc about to collide must NOT
//!    keep predicting a straight line through the impact. The expiry is stated explicitly.
//!  * RELATIVE / IN-PLANE / HORIZON-BOUNDED. Errors are reported as a fraction of the object's own
//!    scale (no absolute SI). Orientation forecasts are the IN-PLANE director only; out-of-plane
//!    orientation stays ABSTAIN (monocular — same bound as orientation_spinor). The horizon is finite.
//!  * SELF-GRADING. The self-validation error is the engine grading ITSELF: a small realised error
//!    corroborates that the certified conservation actually held; a large error means the regime was
//!    mis-certified or a force intervened. The grade does not change the forecast; it scores it.
//!
//! Laws pinned (all green, Init-only, zero-axiom; same provenance as object_intel.rs):
//!  - free translation (linear momentum conserved => constant velocity => ballistic position):
//!    `ForkRaceFoldVentAreForces.fork_preserves_charge` — p transported unchanged over the window, so
//!    pos(t+Δt) = pos + v·Δt.
//!  - free rotation (angular momentum conserved => constant ω => the spinor sheet advances linearly):
//!    `ForkRaceFoldVentAreForces.fork_preserves_charge` — L transported unchanged, so the in-plane
//!    director(t+Δt) = director_unwrapped + ω·Δt.
//!  - at rest (a contracting, non-spinning centroid stays put): `VacuumIsOnlyForce.vacuum_force_contracts`.

use crate::object_intel::{Regime, RigidProfile};
use crate::physics::Verdict;
use crate::scene::SceneObject;

const LAW_CONSERVE: &str = "ForkRaceFoldVentAreForces.fork_preserves_charge";
const LAW_REST: &str = "VacuumIsOnlyForce.vacuum_force_contracts";

/// What kind of state a forecast asserts (the certified channel of the prediction).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ForecastKind {
    /// Ballistic position forecast (free_translation, linear momentum conserved).
    Position,
    /// In-plane director forecast (free_rotation, angular momentum conserved).
    Orientation,
    /// Stays-put forecast (at_rest).
    Rest,
    /// No forecast asserted (forced / abstain / regime not yet held / lift unreliable).
    Abstain,
}

impl ForecastKind {
    pub fn as_str(self) -> &'static str {
        match self {
            ForecastKind::Position => "position(ballistic)",
            ForecastKind::Orientation => "orientation(in-plane)",
            ForecastKind::Rest => "rest(stays-put)",
            ForecastKind::Abstain => "abstain",
        }
    }
}

/// A certified, CONDITIONAL forecast of one object's state at a future presentation time.
#[derive(Debug, Clone)]
pub struct Forecast {
    pub id: u64,
    /// The regime that issued the forecast (the conservation law that holds the object).
    pub regime: Regime,
    pub kind: ForecastKind,
    /// §7.5 verdict: Accept = a certified conditional forecast; Abstain = no honest forecast.
    pub verdict: Verdict,
    pub law: &'static str,
    /// Human-readable conditional statement ("IF no new force, THEN ...").
    pub statement: String,

    /// pts at which the forecast was ISSUED (the object's last observation when predicting).
    pub issued_pts: f64,
    /// pts the forecast targets = issued_pts + horizon.
    pub target_pts: f64,
    /// Horizon Δt in seconds.
    pub horizon_s: f32,
    /// Frames the regime had held (inclusive) when the forecast was issued — the validity window.
    pub held_frames: u32,

    // --- the predicted state (only the channel matching `kind` is meaningful) ---
    /// Predicted centroid (normalised frame coords) for a Position forecast.
    pub pred_x: f32,
    pub pred_y: f32,
    /// Predicted in-plane director lift (radians, continuous) for an Orientation forecast.
    pub pred_director_unwrapped: f32,
    /// Object characteristic size at issue (the relative scale for the self-validation error).
    pub scale: f32,

    /// True once the forecast has been INVALIDATED by an imminent/actual interaction before its
    /// horizon (the free-motion assumption broke). An invalidated forecast is not self-graded as a
    /// conservation failure — the conservation was never claimed to survive the force.
    pub invalidated: bool,
    /// If invalidated, why (e.g. "imminent collision with #7 (approaching, within 1.2x size)").
    pub invalidation_reason: Option<String>,
}

impl Forecast {
    /// A one-line statement of the forecast (or its abstain).
    pub fn line(&self) -> String {
        if self.verdict == Verdict::Abstain {
            return format!("#{} ABSTAIN ({}): {}", self.id, self.regime.as_str(), self.statement);
        }
        format!(
            "#{} {} [{}] held {}f, horizon {:.3}s @pts {:.3}->{:.3}: {}",
            self.id,
            self.kind.as_str(),
            self.regime.as_str(),
            self.held_frames,
            self.horizon_s,
            self.issued_pts,
            self.target_pts,
            self.statement
        )
    }
}

/// The realised self-validation of a forecast, graded once the clip reached (or passed) the horizon.
#[derive(Debug, Clone)]
pub struct Validation {
    pub id: u64,
    pub kind: ForecastKind,
    pub regime: Regime,
    pub issued_pts: f64,
    pub target_pts: f64,
    /// pts of the ACTUAL observation used to grade (closest to target_pts).
    pub realized_pts: f64,
    pub horizon_s: f32,

    /// Predicted vs realised, in the forecast's channel.
    /// Position: |pred_pos - actual_pos| (normalised distance). Orientation: |Δdirector| (radians).
    pub raw_error: f32,
    /// The error as a FRACTION of the object's scale: position error / char_size, or orientation
    /// error / (2π) (a full turn). This is the engine grading itself, relative-scale.
    pub rel_error: f32,
    /// Was the forecast invalidated before its horizon (a force/collision intervened)?
    pub invalidated: bool,
    pub invalidation_reason: Option<String>,
    /// The verdict of the GRADE: Accept = realised error within `grade_tol` (the conservation held);
    /// Decline = error beyond tol on a non-invalidated forecast (the regime was mis-certified or an
    /// unmodelled force acted); Abstain = the forecast was invalidated before its horizon (no grade,
    /// the free continuation was correctly retired). Cites the same conservation law.
    pub grade: Verdict,
    pub law: &'static str,
}

impl Validation {
    pub fn line(&self) -> String {
        let g = match self.grade {
            Verdict::Accept => "ACCEPT",
            Verdict::Abstain => "abstain",
            Verdict::Decline => "DECLINE",
        };
        match self.kind {
            ForecastKind::Orientation => format!(
                "#{} {} grade {} : orientation error {:.3} rad = {:.1}% of a turn (regime {}, horizon {:.3}s)",
                self.id, self.kind.as_str(), g, self.raw_error, self.rel_error * 100.0,
                self.regime.as_str(), self.horizon_s
            ),
            _ => format!(
                "#{} {} grade {} : position error {:.4} = {:.1}% of scale (regime {}, horizon {:.3}s)",
                self.id, self.kind.as_str(), g, self.raw_error, self.rel_error * 100.0,
                self.regime.as_str(), self.horizon_s
            ),
        }
    }
}

/// Tunables for the predictor. Defaults favour ABSTAIN over an over-eager forecast.
#[derive(Debug, Clone)]
pub struct PredictionConfig {
    /// Horizon in FRAMES (scene ticks) — converted to seconds via the object's recent frame dt.
    pub horizon_frames: u32,
    /// The regime must have HELD this many consecutive frames before a forecast is asserted (a
    /// better-established conservation => a trustworthy horizon). Below this: ABSTAIN.
    pub hold_min: u32,
    /// Realised error (relative-scale) at/under which the grade is ACCEPT (the conservation held).
    /// Above this (on a non-invalidated forecast): DECLINE.
    pub grade_tol: f32,
    /// Imminent-collision proximity: two objects are on a collision course when their centroid
    /// distance is below this multiple of the sum of their characteristic sizes AND closing.
    pub proximity_factor: f32,
    /// Minimum closing speed (d(distance)/dt < -this, per second) to call a pair APPROACHING.
    pub closing_speed_min: f32,
}

impl Default for PredictionConfig {
    fn default() -> Self {
        PredictionConfig {
            horizon_frames: 8,
            hold_min: 4,
            grade_tol: 0.15,
            proximity_factor: 2.0,
            closing_speed_min: 0.003,
        }
    }
}

/// Per-object predictor state carried across ticks (the scene rebuilds objects every tick; the
/// regime-hold counter and the pending-forecast queue must persist here).
#[derive(Debug, Clone, Default)]
struct ObjState {
    /// The regime the object was in last tick (to detect a regime CHANGE that resets the hold).
    last_regime: Option<Regime>,
    /// Consecutive frames the current regime has held (inclusive of this tick).
    held: u32,
    /// pts of the last observation (to compute the per-object frame dt).
    last_pts: f64,
    /// Mean inter-frame dt (s) over the object's recent observations (for the horizon conversion).
    mean_dt: f32,
}

/// The certified-prediction engine. Issues conditional forecasts, expires them on imminent collision,
/// and self-validates each against the realised state once the clip advances to its horizon.
#[derive(Debug, Clone)]
pub struct Predictor {
    cfg: PredictionConfig,
    /// Per-object hold/timing state (keyed by track id).
    objs: std::collections::HashMap<u64, ObjState>,
    /// Forecasts issued but not yet graded (their target pts is still in the future).
    pending: Vec<Forecast>,
    /// The CURRENT (most-recent-tick) forecast per object, for live reporting.
    pub current: std::collections::HashMap<u64, Forecast>,
    /// All completed self-validations (a forecast graded against the realised state).
    pub validations: Vec<Validation>,
}

impl Predictor {
    pub fn new() -> Self {
        Self::with_config(PredictionConfig::default())
    }

    pub fn with_config(cfg: PredictionConfig) -> Self {
        Predictor {
            cfg,
            objs: std::collections::HashMap::new(),
            pending: Vec::new(),
            current: std::collections::HashMap::new(),
            validations: Vec::new(),
        }
    }

    pub fn config(&self) -> &PredictionConfig {
        &self.cfg
    }

    /// Advance the predictor one tick with this tick's certified objects at presentation time `pts`.
    ///
    /// Three things happen each tick, in order:
    ///  1. GRADE: any pending forecast whose target pts has been reached/passed is self-validated
    ///     against the realised observation (and invalidated forecasts are retired as abstain-grades).
    ///  2. INVALIDATE: any still-pending forecast for an object now on a collision course is expired
    ///     (the free-motion assumption broke before its horizon).
    ///  3. ISSUE: update each object's regime-hold counter and, if its regime is forecastable and has
    ///     held long enough, issue a fresh conditional forecast for t+Δt.
    pub fn observe(&mut self, pts: f64, objects: &[(SceneObject, Verdict)]) {
        // ---- 1. GRADE pending forecasts whose horizon has been reached ----
        // Build a quick lookup of this tick's observed state per id.
        let mut grade_now: Vec<usize> = Vec::new();
        for (i, f) in self.pending.iter().enumerate() {
            // Grade once the clip has reached (or just passed) the forecast's target pts. Using a
            // small tolerance window of half a frame so the closest observation lands the grade.
            if pts + 1e-6 >= f.target_pts {
                grade_now.push(i);
            }
        }
        // Realise grades (collect indices, drain back-to-front to keep indices valid).
        grade_now.sort_unstable();
        for &i in grade_now.iter().rev() {
            let f = self.pending.remove(i);
            let actual = objects.iter().find(|(o, _)| o.id == f.id).map(|(o, _)| o);
            if let Some(v) = self.grade(&f, pts, actual) {
                self.validations.push(v);
            }
        }

        // ---- 2. INVALIDATE pending forecasts on a collision course ----
        for f in self.pending.iter_mut() {
            if f.invalidated {
                continue;
            }
            if let Some(reason) = imminent_collision(f.id, objects, &self.cfg) {
                f.invalidated = true;
                f.invalidation_reason = Some(reason.clone());
                // Mirror onto the live current forecast so the report shows the expiry.
                if let Some(cur) = self.current.get_mut(&f.id) {
                    cur.invalidated = true;
                    cur.invalidation_reason = Some(reason);
                }
            }
        }

        // ---- 3. ISSUE fresh forecasts ----
        // Track which ids are live this tick so we can prune dead per-object state.
        let mut live: std::collections::HashSet<u64> = std::collections::HashSet::new();
        for (obj, _adm) in objects {
            live.insert(obj.id);
            let st = self.objs.entry(obj.id).or_default();
            // Update timing (mean dt over the object's observations).
            if st.last_pts > 0.0 {
                let dt = (pts - st.last_pts).max(1e-3) as f32;
                st.mean_dt = if st.mean_dt <= 0.0 { dt } else { 0.7 * st.mean_dt + 0.3 * dt };
            }
            st.last_pts = pts;

            // Regime-hold counter: reset on a regime CHANGE, increment while it holds.
            let regime = obj.profile.regime;
            match st.last_regime {
                Some(prev) if prev == regime => st.held += 1,
                _ => st.held = 1,
            }
            st.last_regime = Some(regime);

            let held = st.held;
            let dt = if st.mean_dt > 0.0 { st.mean_dt } else { 1.0 / 30.0 };
            let horizon_s = dt * self.cfg.horizon_frames as f32;

            let forecast = self.make_forecast(obj, pts, held, horizon_s);
            // Stage a forecast for self-validation only when it is an asserted (Accept) forecast.
            if forecast.verdict == Verdict::Accept {
                self.pending.push(forecast.clone());
            }
            self.current.insert(obj.id, forecast);
        }

        // Prune state + current forecasts for objects that have left the scene (and are not pending).
        let pending_ids: std::collections::HashSet<u64> = self.pending.iter().map(|f| f.id).collect();
        self.objs.retain(|id, _| live.contains(id));
        self.current.retain(|id, _| live.contains(id) || pending_ids.contains(id));
    }

    /// Build the conditional forecast for one object (pure: reads the object's certified profile and
    /// spinor lift, integrates the regime's conserved quantity forward by `horizon_s`).
    fn make_forecast(&self, obj: &SceneObject, pts: f64, held: u32, horizon_s: f32) -> Forecast {
        let p: &RigidProfile = &obj.profile;
        let scale = p.char_size.max(1e-6);
        let target_pts = pts + horizon_s as f64;

        // Abstain template (forced / abstain regime, or regime not yet held long enough).
        let abstain = |statement: String| Forecast {
            id: obj.id,
            regime: p.regime,
            kind: ForecastKind::Abstain,
            verdict: Verdict::Abstain,
            law: LAW_CONSERVE,
            statement,
            issued_pts: pts,
            target_pts,
            horizon_s,
            held_frames: held,
            pred_x: obj.x,
            pred_y: obj.y,
            pred_director_unwrapped: 0.0,
            scale,
            invalidated: false,
            invalidation_reason: None,
        };

        // Regime must be forecastable at all.
        match p.regime {
            Regime::Forced => {
                return abstain(
                    "forced object (a force/torque is acting) is not predictable -> ABSTAIN".to_string(),
                );
            }
            Regime::Abstain => {
                return abstain(
                    "regime unresolved (no certified conservation) -> ABSTAIN".to_string(),
                );
            }
            _ => {}
        }

        // Regime must have HELD long enough for the conservation to be established.
        if held < self.cfg.hold_min {
            return abstain(format!(
                "{} held only {}f (< {}f); conservation not yet established -> ABSTAIN",
                p.regime.as_str(),
                held,
                self.cfg.hold_min
            ));
        }

        match p.regime {
            Regime::FreeTranslation => {
                // Linear momentum conserved => constant velocity => ballistic position.
                let pred_x = obj.x + p.vx * horizon_s;
                let pred_y = obj.y + p.vy * horizon_s;
                Forecast {
                    id: obj.id,
                    regime: p.regime,
                    kind: ForecastKind::Position,
                    verdict: Verdict::Accept,
                    law: LAW_CONSERVE,
                    statement: format!(
                        "IF no new force, THEN pos(t+{:.3}s) = ({:.4},{:.4}) [ballistic from ({:.4},{:.4}) at v=({:+.4},{:+.4})/s]",
                        horizon_s, pred_x, pred_y, obj.x, obj.y, p.vx, p.vy
                    ),
                    issued_pts: pts,
                    target_pts,
                    horizon_s,
                    held_frames: held,
                    pred_x,
                    pred_y,
                    pred_director_unwrapped: 0.0,
                    scale,
                    invalidated: false,
                    invalidation_reason: None,
                }
            }
            Regime::FreeRotation => {
                // Angular momentum conserved => constant ω => the in-plane director sheet advances
                // linearly. Out-of-plane orientation stays ABSTAIN (monocular — see header).
                match p.omega {
                    Some(w) => {
                        let dir0 = obj_director_unwrapped(obj);
                        let pred_dir = dir0 + w * horizon_s;
                        Forecast {
                            id: obj.id,
                            regime: p.regime,
                            kind: ForecastKind::Orientation,
                            verdict: Verdict::Accept,
                            law: LAW_CONSERVE,
                            statement: format!(
                                "IF no new torque, THEN in-plane director(t+{:.3}s) = {:.4} rad [from {:.4} at ω={:+.4} rad/s]; out-of-plane orientation ABSTAINS (monocular)",
                                horizon_s, pred_dir, dir0, w
                            ),
                            issued_pts: pts,
                            target_pts,
                            horizon_s,
                            held_frames: held,
                            pred_x: obj.x,
                            pred_y: obj.y,
                            pred_director_unwrapped: pred_dir,
                            scale,
                            invalidated: false,
                            invalidation_reason: None,
                        }
                    }
                    None => abstain(
                        "free_rotation certified but in-plane lift unreliable (out-of-plane/monocular): ω abstains -> no orientation forecast".to_string(),
                    ),
                }
            }
            Regime::AtRest => Forecast {
                id: obj.id,
                regime: p.regime,
                kind: ForecastKind::Rest,
                verdict: Verdict::Accept,
                law: LAW_REST,
                statement: format!(
                    "IF no new force, THEN pos(t+{:.3}s) = ({:.4},{:.4}) [stays put: contracting, non-spinning centroid]",
                    horizon_s, obj.x, obj.y
                ),
                issued_pts: pts,
                target_pts,
                horizon_s,
                held_frames: held,
                pred_x: obj.x,
                pred_y: obj.y,
                pred_director_unwrapped: 0.0,
                scale,
                invalidated: false,
                invalidation_reason: None,
            },
            // Handled above.
            Regime::Forced | Regime::Abstain => abstain("not forecastable".to_string()),
        }
    }

    /// Self-validate one forecast against the realised observation. Returns None if the object is no
    /// longer observable at the horizon (a dropped track — no honest grade is possible).
    fn grade(&self, f: &Forecast, realized_pts: f64, actual: Option<&SceneObject>) -> Option<Validation> {
        // An invalidated forecast is retired as an ABSTAIN grade: the free continuation was correctly
        // expired by an intervening force/collision, so it must NOT be scored as a conservation failure.
        if f.invalidated {
            return Some(Validation {
                id: f.id,
                kind: f.kind,
                regime: f.regime,
                issued_pts: f.issued_pts,
                target_pts: f.target_pts,
                realized_pts,
                horizon_s: f.horizon_s,
                raw_error: 0.0,
                rel_error: 0.0,
                invalidated: true,
                invalidation_reason: f.invalidation_reason.clone(),
                grade: Verdict::Abstain,
                law: f.law,
            });
        }

        // The track must still be observable to grade (otherwise: no honest comparison).
        let obj = actual?;

        let (raw_error, rel_error) = match f.kind {
            ForecastKind::Position | ForecastKind::Rest => {
                let dx = obj.x - f.pred_x;
                let dy = obj.y - f.pred_y;
                let raw = (dx * dx + dy * dy).sqrt();
                (raw, raw / f.scale.max(1e-6))
            }
            ForecastKind::Orientation => {
                let actual_dir = obj_director_unwrapped(obj);
                let raw = (actual_dir - f.pred_director_unwrapped).abs();
                // Relative to a full physical turn (2π) — a turn is the natural orientation scale.
                (raw, raw / std::f32::consts::TAU)
            }
            ForecastKind::Abstain => (0.0, 0.0),
        };

        // GRADE: within tol => the conservation held (Accept); beyond => mis-certified / unmodelled
        // force (Decline). The grade is the engine scoring itself; it never alters the forecast.
        let grade = if rel_error <= self.cfg.grade_tol {
            Verdict::Accept
        } else {
            Verdict::Decline
        };

        Some(Validation {
            id: f.id,
            kind: f.kind,
            regime: f.regime,
            issued_pts: f.issued_pts,
            target_pts: f.target_pts,
            realized_pts,
            horizon_s: f.horizon_s,
            raw_error,
            rel_error,
            invalidated: false,
            invalidation_reason: None,
            grade,
            law: f.law,
        })
    }

    /// A one-line scene summary of the self-validation: how well the certified regimes held.
    /// E.g. "3 forecasts graded: 2 accept (held), 1 abstain (invalidated by collision)".
    pub fn validation_summary(&self) -> String {
        let n = self.validations.len();
        if n == 0 {
            return "0 forecasts graded".to_string();
        }
        let acc = self.validations.iter().filter(|v| v.grade == Verdict::Accept).count();
        let dec = self.validations.iter().filter(|v| v.grade == Verdict::Decline).count();
        let abs = self.validations.iter().filter(|v| v.grade == Verdict::Abstain).count();
        let mut parts = Vec::new();
        if acc > 0 { parts.push(format!("{acc} accept (conservation held)")); }
        if dec > 0 { parts.push(format!("{dec} decline (regime broke / mis-certified)")); }
        if abs > 0 { parts.push(format!("{abs} abstain (invalidated by interaction)")); }
        format!("{n} forecast{} graded: {}", if n == 1 { "" } else { "s" }, parts.join(", "))
    }
}

impl Default for Predictor {
    fn default() -> Self {
        Self::new()
    }
}

/// The object's current in-plane director lift (continuous, radians) from its profile's spinor.
/// SceneObject does not carry the spinor directly; it carries the live ω in the profile and the
/// continuous director is read from the same source the regime used. We expose it via the object's
/// carried `director_unwrapped` (added to SceneObject for the forecast hook).
#[inline]
fn obj_director_unwrapped(obj: &SceneObject) -> f32 {
    obj.director_unwrapped
}

/// Is `id` on a collision course this tick? Returns the reason if it is close to AND approaching
/// another object (the free-motion assumption is about to break). Pure proximity+closing test over
/// the scene's current objects — it does NOT run the after-the-fact interaction detector.
fn imminent_collision(
    id: u64,
    objects: &[(SceneObject, Verdict)],
    cfg: &PredictionConfig,
) -> Option<String> {
    let me = objects.iter().find(|(o, _)| o.id == id).map(|(o, _)| o)?;
    let my_size = me.profile.char_size.max(1e-6);
    for (other, _) in objects {
        if other.id == id {
            continue;
        }
        let other_size = other.profile.char_size.max(1e-6);
        let dx = other.x - me.x;
        let dy = other.y - me.y;
        let dist = (dx * dx + dy * dy).sqrt();
        let contact = cfg.proximity_factor * (my_size + other_size);
        if dist > contact {
            continue;
        }
        // Closing speed: rate of change of separation = -(relative velocity · unit separation).
        // d/dt|r| = (r · v_rel)/|r|, where v_rel = v_other - v_me. Negative => closing.
        let rvx = other.vx - me.vx;
        let rvy = other.vy - me.vy;
        let inv = 1.0 / dist.max(1e-6);
        let dsep = (dx * rvx + dy * rvy) * inv; // d|r|/dt
        if dsep < -cfg.closing_speed_min {
            return Some(format!(
                "imminent collision with #{} (approaching: separation {:.4} < {:.4}, closing {:.4}/s)",
                other.id, dist, contact, -dsep
            ));
        }
    }
    None
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::object_intel::RigidProfile;

    fn mk_profile(id: u64, regime: Regime, vx: f32, vy: f32, omega: Option<f32>, char_size: f32) -> RigidProfile {
        RigidProfile {
            id,
            genus: 0,
            silhouette_area: 0.05,
            char_size,
            depth: 0.5,
            volume: 0.025,
            mass: 0.025,
            density: crate::object_intel::DENSITY_GUESS,
            material: crate::object_intel::MaterialKind::Unknown,
            grounded: false,
            inertia_spin: 0.001,
            vx,
            vy,
            speed: (vx * vx + vy * vy).sqrt(),
            momentum: 0.0,
            ke_lin: 0.0,
            omega,
            ang_momentum: omega.map(|w| 0.001 * w),
            ke_rot: omega.map(|w| 0.5 * 0.001 * w * w),
            regime,
            facts: Vec::new(),
            momentum_spread: f32::INFINITY,
            ang_spread: None,
            hold_frames: 0,
            abstain_reason: crate::object_intel::AbstainReason::None,
        }
    }

    fn mk_obj(id: u64, x: f32, y: f32, vx: f32, vy: f32, dir: f32, regime: Regime, omega: Option<f32>) -> SceneObject {
        SceneObject {
            id,
            x,
            y,
            vx,
            vy,
            speed: (vx * vx + vy * vy).sqrt(),
            bw: 0.1,
            bh: 0.1,
            genus: 0,
            director_unwrapped: dir,
            profile: mk_profile(id, regime, vx, vy, omega, 0.1),
            luma_sig: [0u8; 64],
        }
    }

    fn cfg_fast() -> PredictionConfig {
        // hold_min=2 so a couple of ticks issue a forecast; small horizon for the tests.
        PredictionConfig { horizon_frames: 4, hold_min: 2, grade_tol: 0.15, proximity_factor: 2.0, closing_speed_min: 0.003 }
    }

    #[test]
    fn free_translation_predicts_ballistic_position() {
        // A steadily-translating disc held >= hold_min frames issues a ballistic position forecast.
        let mut pred = Predictor::with_config(cfg_fast());
        let dt = 1.0 / 30.0;
        let v = 0.5f32;
        for k in 0..4 {
            let pts = k as f64 * dt as f64;
            let x = 0.1 + v * pts as f32;
            let obj = mk_obj(1, x, 0.5, v, 0.0, 0.0, Regime::FreeTranslation, None);
            pred.observe(pts, &[(obj, Verdict::Accept)]);
        }
        let f = pred.current.get(&1).expect("forecast present");
        assert_eq!(f.verdict, Verdict::Accept, "{}", f.line());
        assert_eq!(f.kind, ForecastKind::Position);
        // pred_x = x + v*horizon; horizon = 4 frames * dt.
        let last_x = 0.1 + v * (3.0 * dt);
        let expect = last_x + v * (4.0 * dt);
        assert!((f.pred_x - expect).abs() < 1e-3, "pred_x {} expect {}", f.pred_x, expect);
        assert!(f.law.contains("fork_preserves_charge"));
    }

    #[test]
    fn free_rotation_predicts_in_plane_director() {
        // A free-rotating bar with constant ω issues an in-plane director forecast.
        let mut pred = Predictor::with_config(cfg_fast());
        let dt = 1.0 / 30.0;
        let w = 2.0f32; // rad/s
        for k in 0..4 {
            let pts = k as f64 * dt as f64;
            let dir = w * pts as f32;
            let obj = mk_obj(2, 0.5, 0.5, 0.0, 0.0, dir, Regime::FreeRotation, Some(w));
            pred.observe(pts, &[(obj, Verdict::Accept)]);
        }
        let f = pred.current.get(&2).expect("forecast present");
        assert_eq!(f.kind, ForecastKind::Orientation, "{}", f.line());
        assert_eq!(f.verdict, Verdict::Accept);
        let last_dir = w * (3.0 * dt);
        let expect = last_dir + w * (4.0 * dt);
        assert!((f.pred_director_unwrapped - expect).abs() < 1e-3, "pred {} expect {}", f.pred_director_unwrapped, expect);
    }

    #[test]
    fn forced_object_abstains() {
        let mut pred = Predictor::with_config(cfg_fast());
        for k in 0..5 {
            let pts = k as f64 / 30.0;
            let obj = mk_obj(3, 0.2, 0.2, 0.3, 0.0, 0.0, Regime::Forced, None);
            pred.observe(pts, &[(obj, Verdict::Accept)]);
        }
        let f = pred.current.get(&3).expect("present");
        assert_eq!(f.verdict, Verdict::Abstain, "forced must not forecast: {}", f.line());
        assert_eq!(f.kind, ForecastKind::Abstain);
        assert!(pred.validations.is_empty(), "forced object stages no forecast => no grade");
    }

    #[test]
    fn short_hold_abstains_then_asserts() {
        // Below hold_min the regime is not yet established => abstain; at/after => assert.
        let mut pred = Predictor::with_config(cfg_fast());
        // tick 0: held=1 < hold_min(2) => abstain.
        pred.observe(0.0, &[(mk_obj(4, 0.1, 0.5, 0.4, 0.0, 0.0, Regime::FreeTranslation, None), Verdict::Accept)]);
        assert_eq!(pred.current.get(&4).unwrap().verdict, Verdict::Abstain);
        // tick 1: held=2 == hold_min => assert.
        pred.observe(1.0 / 30.0, &[(mk_obj(4, 0.11, 0.5, 0.4, 0.0, 0.0, Regime::FreeTranslation, None), Verdict::Accept)]);
        assert_eq!(pred.current.get(&4).unwrap().verdict, Verdict::Accept);
    }

    #[test]
    fn self_validation_small_error_on_truly_ballistic() {
        // A truly-ballistic disc: the forecast issued at frame t should match the realised state at
        // t+horizon with a small relative error => grade ACCEPT.
        let mut pred = Predictor::with_config(cfg_fast());
        let dt = 1.0 / 30.0;
        let v = 0.3f32;
        for k in 0..16 {
            let pts = k as f64 * dt as f64;
            let x = 0.05 + v * pts as f32;
            let obj = mk_obj(5, x, 0.5, v, 0.0, 0.0, Regime::FreeTranslation, None);
            pred.observe(pts, &[(obj, Verdict::Accept)]);
        }
        assert!(!pred.validations.is_empty(), "some forecasts must have been graded");
        let acc = pred.validations.iter().filter(|v| v.grade == Verdict::Accept).count();
        assert!(acc > 0, "truly-ballistic motion must self-validate ACCEPT");
        // The realised error should be small (well under tol) for the constant-velocity case.
        let best = pred.validations.iter().map(|v| v.rel_error).fold(f32::INFINITY, f32::min);
        assert!(best < 0.05, "ballistic self-validation error must be small, got {best}");
    }

    #[test]
    fn invalidation_expires_forecast_before_collision() {
        // Two discs closing head-on: the free-translation forecast must be INVALIDATED (not graded as
        // a conservation failure) before the horizon.
        let mut pred = Predictor::with_config(cfg_fast());
        let dt = 1.0 / 30.0;
        // Establish the regime with a few separated frames, then bring a second disc into contact.
        for k in 0..6 {
            let pts = k as f64 * dt as f64;
            let xa = 0.3 + 0.4 * pts as f32; // moving right
            let xb = 0.7 - 0.4 * pts as f32; // moving left, closing
            let a = mk_obj(6, xa, 0.5, 0.4, 0.0, 0.0, Regime::FreeTranslation, None);
            let b = mk_obj(7, xb, 0.5, -0.4, 0.0, 0.0, Regime::FreeTranslation, None);
            pred.observe(pts, &[(a, Verdict::Accept), (b, Verdict::Accept)]);
        }
        // At least one of #6's forecasts must have been invalidated by the closing #7.
        let invalidated_grade = pred
            .validations
            .iter()
            .any(|v| v.id == 6 && v.invalidated && v.grade == Verdict::Abstain);
        let live_invalidated = pred.current.get(&6).map(|f| f.invalidated).unwrap_or(false);
        assert!(
            invalidated_grade || live_invalidated,
            "closing pair must invalidate the straight-line forecast; validations: {:?}",
            pred.validations.iter().map(|v| (v.id, v.invalidated, v.grade)).collect::<Vec<_>>()
        );
    }

    #[test]
    fn at_rest_predicts_stay_put() {
        let mut pred = Predictor::with_config(cfg_fast());
        for k in 0..5 {
            let pts = k as f64 / 30.0;
            let obj = mk_obj(8, 0.5, 0.5, 0.0, 0.0, 0.0, Regime::AtRest, None);
            pred.observe(pts, &[(obj, Verdict::Accept)]);
        }
        let f = pred.current.get(&8).expect("present");
        assert_eq!(f.kind, ForecastKind::Rest, "{}", f.line());
        assert_eq!(f.verdict, Verdict::Accept);
        assert!(f.law.contains("vacuum_force_contracts"));
        assert!((f.pred_x - 0.5).abs() < 1e-6 && (f.pred_y - 0.5).abs() < 1e-6);
    }
}
